#!/usr/bin/env node
// Enriches structured_list items with body text
// Run: node scripts/enrich-bodies.mjs

import { readFileSync, writeFileSync } from 'fs'

// Body text lookup: keyed by "taskId::primary"
const bodies = {}

function b(taskId, primary, body) { bodies[taskId + '::' + primary] = body }

// ============================================================
// PHILOSOPHY — philosophical_literacy
// ============================================================

// ph-001: Branches of philosophy
b('ph-001', 'Epistemology', "Epistemology asks: how do we know what we know? When you say 'I know the earth is round,' what makes that knowledge rather than just belief? Epistemologists distinguish between types of knowledge — knowing facts (propositional), knowing how to do things (procedural), and knowing people or places (acquaintance). The key debate: is knowledge 'justified true belief,' or is that not enough? Gettier showed in 1963 that you can have justified true belief and still be wrong by luck.")
b('ph-001', 'Ethics', "Ethics is the branch you're already doing every day without realizing it. Every time you decide whether to tell a white lie, tip a waiter, or call out unfair behavior, you're doing ethics. The field splits into three layers: meta-ethics (what IS morality?), normative ethics (what SHOULD we do?), and applied ethics (specific issues like abortion or AI). Most everyday moral arguments are normative — people disagreeing about which rules or values should guide action.")
b('ph-001', 'Metaphysics', "Metaphysics tackles the questions that keep you up at 2 AM. Do you have free will, or is every choice predetermined by physics? What makes you 'you' — your body, your memories, your consciousness? Is time real or just how humans perceive change? These aren't just abstract puzzles. Your answer to 'do we have free will?' changes how you think about criminal punishment, personal responsibility, and whether praise or blame make sense.")

// ph-002: Foundational philosophers
b('ph-002', 'Socrates', "Socrates never wrote a single word — everything we know comes from his student Plato. He wandered Athens asking powerful people uncomfortable questions until they realized they didn't actually know what they claimed to know. His method was simple: keep asking 'why?' and 'what do you mean by that?' until the other person's argument collapsed. Athens eventually executed him for 'corrupting the youth,' which really meant he made important people look foolish in public.")
b('ph-002', 'Plato', "Plato's big idea is wild: everything you see — this chair, that tree, your dog — is an imperfect copy of a perfect 'Form' that exists in a non-physical realm. The Form of a chair is the perfect chair-ness that all chairs participate in. His famous Cave allegory illustrates this: imagine prisoners who've only ever seen shadows on a wall. They think shadows ARE reality. Philosophy is the process of turning around and seeing the actual objects casting the shadows.")
b('ph-002', 'Aristotle', "Aristotle was Plato's student but disagreed with him on almost everything. Where Plato looked up to abstract ideals, Aristotle looked around at the actual world — he classified animals, studied constitutions, and analyzed poetry. His key ethical insight: virtue isn't about following rules, it's about developing good character through practice. You become brave by doing brave things, honest by practicing honesty. He essentially invented the idea that excellence is a habit, not an act.")
b('ph-002', 'René Descartes', "Descartes decided to doubt absolutely everything to find one thing he couldn't doubt. Maybe his senses were lying. Maybe the world was fake. Maybe an evil demon was tricking him. But even if everything was an illusion, the fact that he was THINKING about it proved he existed. 'Cogito ergo sum' — I think, therefore I am. This one move launched modern philosophy by making the thinking self, rather than God or nature, the starting point for knowledge.")
b('ph-002', 'Immanuel Kant', "Kant is the philosopher who tried to save morality from being just personal opinion. His test: before you act, ask 'what if EVERYONE did this?' If you want to lie to get out of trouble, imagine a world where everyone lies — trust collapses and lying becomes pointless. The rule contradicts itself. Kant argued this test (the Categorical Imperative) gives us objective moral rules that don't depend on consequences, feelings, or culture. Critics say it's too rigid — but it's remarkably powerful.")
b('ph-002', 'Friedrich Nietzsche', "Nietzsche is the most misunderstood philosopher in history. 'God is dead' wasn't a celebration — it was a warning. If traditional religion no longer provides meaning, what fills the void? Nihilism? Nationalism? Consumerism? Nietzsche's answer was radical self-creation: become who you are, create your own values, embrace life fully including its suffering. He wasn't anti-morality — he was against blindly inheriting morality without examining it. His writing style is poetic, provocative, and deliberately unsettling.")

// ph-003: Thought experiments
b('ph-003', 'Trolley Problem', "A runaway trolley is heading toward five people. You can pull a lever to divert it to a side track where it will kill one person instead. Most people say: pull the lever. But now imagine you're on a bridge and can push a large stranger onto the tracks to stop the trolley — same math, one dies to save five. Most people refuse. This inconsistency is the whole point: it reveals that we don't just care about outcomes. Something about the ACT of pushing feels different from pulling a lever.")
b('ph-003', 'Brain in a Vat', "Imagine scientists removed your brain, put it in a jar, and connected it to a computer feeding you perfectly realistic fake experiences. You'd feel, see, and hear everything as normal. How would you know? You couldn't. This isn't just sci-fi — it's a serious challenge to the idea that our senses give us reliable knowledge about reality. The Matrix borrowed this idea directly. Descartes raised the same worry in the 1600s with his 'evil demon' scenario.")
b('ph-003', 'Ship of Theseus', "An ancient ship is preserved in a museum. Over centuries, every rotting plank is replaced with new wood. Eventually no original material remains. Is it still the same ship? Now imagine someone collected all the old planks and rebuilt the original. Which one is the 'real' Ship of Theseus? This puzzle applies to you: your body replaces most of its cells every 7-15 years. Are you the same person you were at age 10? What makes identity persist through change?")
b('ph-003', 'Chinese Room', "Imagine you're locked in a room with a rulebook. Chinese characters are slid under the door. You follow the rules to produce Chinese responses and slide them back. To people outside, it looks like you understand Chinese — but you don't understand a word. You're just following rules mechanically. Searle argued this is exactly what computers do: they manipulate symbols without understanding meaning. It's the strongest argument against the idea that AI can truly 'think.'")

// ph-004: Schools of thought
b('ph-004', 'Stoicism', "Stoicism isn't about suppressing emotions — that's a common misconception. It's about recognizing what's in your control (your reactions, choices, effort) and what isn't (other people, weather, the economy). Marcus Aurelius, a Roman emperor, practiced Stoicism while running an empire and fighting wars. His private journal, Meditations, is basically a self-help book written 2,000 years ago. The core practice: when something upsets you, ask 'is this within my control?' If not, let it go.")
b('ph-004', 'Epicureanism', "Epicurus gets a bad rap. People think Epicureanism means 'eat, drink, and be merry' — but Epicurus actually lived on bread and water. His point was that the SIMPLEST pleasures are the best: a good conversation with friends, freedom from anxiety, a quiet afternoon thinking. He argued that chasing luxury and status creates more pain than pleasure. His school, the Garden, was one of the first to admit women and enslaved people as equal members — radical for 300 BC.")
b('ph-004', 'Existentialism', "Existentialism starts with a terrifying idea: there's no script for your life. You weren't born with a purpose, a destiny, or a nature that determines who you should be. You exist first, then you define yourself through your choices. Sartre captured this as 'existence precedes essence.' The flip side of this freedom is total responsibility — you can't blame your parents, your culture, or your circumstances. Your life is your project, and you're the only author.")
b('ph-004', 'Pragmatism', "Pragmatism is the most American philosophy — literally invented in the US by Charles Peirce, William James, and John Dewey. Its core idea: stop asking 'is this TRUE in some abstract sense?' and start asking 'does this WORK?' If believing in free will makes you take responsibility for your life, then free will is 'true enough.' James applied this to religion: if belief in God makes someone's life better and more moral, that belief has practical truth. Critics call this intellectually lazy; fans call it refreshingly honest.")
b('ph-004', 'Absurdism', "Albert Camus looked at the universe and saw no inherent meaning — no God, no cosmic plan, no purpose written into reality. But instead of despair (nihilism) or inventing meaning (existentialism), he proposed a third option: acknowledge the absurdity AND live fully anyway. His symbol is Sisyphus, condemned to push a boulder uphill forever, watching it roll back down each time. Camus says: 'One must imagine Sisyphus happy.' The rebellion against meaninglessness IS the meaning.")

// ph-006: Logic building blocks
b('ph-006', 'Premise', "A premise is any statement you're treating as true to support your conclusion. 'All humans are mortal' is a premise. 'Socrates is human' is another premise. Together they support the conclusion 'Socrates is mortal.' The tricky part: premises can be unstated. When someone says 'she's a doctor, so she must be smart,' the hidden premise is 'all doctors are smart' — which is debatable. Finding hidden premises is one of the most useful critical thinking skills you can develop.")
b('ph-006', 'Conclusion', "The conclusion is what the argument is trying to prove — the 'therefore' statement. It should follow logically from the premises. A common mistake: people state conclusions as if they're obvious without providing premises. 'We should ban social media for kids' is a conclusion. Without premises (why? what evidence?), it's just an assertion. Tip: look for signal words like 'therefore,' 'so,' 'thus,' 'it follows that' — they usually introduce the conclusion.")
b('ph-006', 'Deduction', "Deductive reasoning gives you certainty — IF the premises are true, the conclusion MUST be true. 'All mammals breathe air. Whales are mammals. Therefore whales breathe air.' There's no wiggle room. The downside: deduction can only rearrange what you already know. It can't discover new facts about the world. That's why science relies more on induction. Deduction is the backbone of mathematics, formal logic, and legal reasoning where certainty matters.")
b('ph-006', 'Induction', "Inductive reasoning is how you navigate daily life. You've seen the sun rise every morning, so you conclude it will rise tomorrow. You've met five friendly dogs, so you assume the next dog will be friendly. Induction gives you probability, not certainty — and sometimes it fails spectacularly. Europeans believed all swans were white until they discovered black swans in Australia. David Hume pointed out that no amount of past observations can logically guarantee future ones. This is called the 'problem of induction.'")

// ph-007: Free will
b('ph-007', 'Hard Determinism', "Hard determinism says your feeling of choosing is an illusion. Every thought you have, every 'decision' you make, was determined by prior causes stretching back to the Big Bang. Your brain is made of atoms following physical laws — where's the room for free choice? Neuroscientist Benjamin Libet found that brain activity for a decision begins BEFORE you're consciously aware of deciding. If your brain decides before 'you' do, who's really in charge? This view has radical implications for criminal justice — can you punish someone for something they couldn't have avoided?")
b('ph-007', 'Libertarian Free Will', "Not the political kind — philosophical libertarianism about free will says humans genuinely can choose otherwise. Something about consciousness or the will escapes the causal chain of physics. Philosopher Robert Kane argues that at key moments of inner conflict, the outcome is genuinely undetermined — you could go either way. Critics ask: if your choice isn't determined by your character, reasons, or desires, then isn't it just random? And random isn't the same as free. This is the libertarian's biggest challenge.")
b('ph-007', 'Compatibilism', "Compatibilism is the most popular position among professional philosophers. It says: yes, your choices are caused by prior events (your desires, beliefs, character). But that's not a problem — that's what free will IS. You're 'free' when you act on your own desires without external coercion. A prisoner forced to work isn't free. A person who chooses to work because they love it IS free — even if that love was shaped by their upbringing. The key distinction: being caused is not the same as being coerced.")

// ph-009: Empiricism vs Rationalism
b('ph-009', 'Empiricism', "Empiricists say the mind starts as a blank slate — John Locke's famous 'tabula rasa.' Everything you know, you learned through your five senses. See enough sunrises and you learn the sun rises daily. Taste enough lemons and you learn they're sour. David Hume took this further: even cause and effect is just a habit of observation. You see billiard ball A hit ball B, and B moves. But you never actually SEE the 'causing' — you just see one event followed by another. Empiricism is the philosophical foundation of modern science.")
b('ph-009', 'Rationalism', "Rationalists argue some knowledge is built into the mind or discoverable through pure reason. Consider mathematics: you don't need to observe anything to know that 2+2=4 or that a triangle's angles sum to 180°. Descartes argued that the idea of God, the concept of infinity, and basic logical truths are innate — no amount of sensory experience could produce them. Leibniz pointed out that necessary truths (like math) can't come from experience, because experience only shows what IS, not what MUST be.")
b('ph-009', 'A priori', "A priori knowledge is what you can know without any experience at all. 'All bachelors are unmarried' — you don't need to survey bachelors to know this. It's true by definition. Mathematical truths are the clearest examples: 7+5=12 is true regardless of what you observe. Kant argued that even the structure of space and time is a priori — your mind imposes spatial and temporal order on experience, rather than learning it from experience. This was his revolutionary 'Copernican turn' in philosophy.")
b('ph-009', 'A posteriori', "A posteriori knowledge requires experience — you have to go out and look. 'Water boils at 100°C at sea level' is a posteriori: someone had to actually heat water and measure. 'There are eight planets in our solar system' required telescopes and observation. The interesting cases are borderline: is 'nothing can be red and green all over at the same time' a priori (knowable by logic) or a posteriori (you need to see colors to know this)? This boundary is still debated.")

// ph-010: Social contract
b('ph-010', 'Hobbes', "Thomas Hobbes lived through the English Civil War and it shaped everything he wrote. He imagined life without government — the 'state of nature' — and concluded it would be a war of all against all. Without laws, anyone could kill you for your stuff. His solution: everyone surrenders their freedom to an absolute sovereign (a king or assembly) who maintains order through force. Yes, you lose liberty — but you gain security. Hobbes essentially argued that even a bad government is better than no government.")
b('ph-010', 'Locke', "John Locke had a much sunnier view of human nature than Hobbes. He believed people in the state of nature would mostly get along, respecting each other's natural rights to life, liberty, and property. Government exists to PROTECT these pre-existing rights, not to grant them. And here's the revolutionary part: if a government violates the rights it was created to protect, the people have the right to overthrow it. This idea directly inspired the American Declaration of Independence and the French Revolution.")
b('ph-010', 'Rousseau', "Rousseau flipped the script entirely. He argued that humans in the state of nature were peaceful, compassionate, and free — it was CIVILIZATION that corrupted them. Private property created inequality, cities created competition, and social hierarchies created envy. His solution wasn't to go back to nature but to create a government based on the 'general will' — what the community as a whole truly wants, not just what the majority votes for. This distinction between popular vote and general will is still debated in democratic theory.")

// ph-016: Phenomenology
b('ph-016', 'Phenomenology', "Phenomenology is the study of how things APPEAR to consciousness, not how they 'really are.' When you see a red apple, a physicist describes wavelengths of light. A phenomenologist asks: what is the EXPERIENCE of seeing red actually like? This 'what it's like' quality of experience is what philosophers call 'qualia.' Phenomenology became hugely influential in psychology, psychiatry, and AI research — because understanding consciousness requires understanding experience from the inside, not just measuring brain activity.")
b('ph-016', 'Husserl', "Edmund Husserl wanted philosophy to be as rigorous as mathematics. His method: 'bracket' all your assumptions about whether things are real, and just describe what appears in consciousness. Don't ask 'does this table exist?' — ask 'what is my experience of this table?' This sounds strange, but it's powerful. By stripping away theories and assumptions, you get to the raw structure of experience. Husserl called this the 'phenomenological reduction' — reducing experience to its essential features.")
b('ph-016', 'Heidegger', "Martin Heidegger, Husserl's student, took phenomenology in a radical direction. He argued we don't experience the world as detached observers — we're always already IN it, using things, caring about outcomes, projecting into the future. You don't see a hammer as 'an object with properties' — you see it as something-for-hammering. This 'being-in-the-world' means understanding can't be separated from living. Heidegger's work is notoriously difficult to read but profoundly influenced existentialism, hermeneutics, and postmodernism.")
b('ph-016', 'Intentionality', "Intentionality doesn't mean 'doing something on purpose.' In philosophy, it means consciousness is always ABOUT something — always directed at an object. You can't just 'be afraid' — you're afraid OF something. You can't just 'believe' — you believe THAT something. Even imagination is intentional: you imagine SOMETHING. This seems obvious, but it has deep implications. It means consciousness isn't a container that holds thoughts — it's more like a spotlight that's always pointing at something. There's no 'empty' consciousness.")

// ============================================================
// PHILOSOPHY — ethics
// ============================================================

// ph-021: Ethical frameworks
b('ph-021', 'Utilitarianism', "Utilitarianism is beautifully simple: the right action is whatever produces the most happiness for the most people. Invented by Jeremy Bentham in the 1700s, it was revolutionary because it treated everyone's happiness as equally important — a king's pleasure counts no more than a peasant's. The appeal is obvious: it gives you a clear decision procedure. The problem is also obvious: it could justify horrifying things (torturing one person to make a million people slightly happier) if the math works out.")
b('ph-021', 'Deontology', "Deontology says some actions are right or wrong regardless of their consequences. Lying is wrong even if it produces good outcomes. Keeping promises is right even when breaking them would help more people. Kant's version is the most famous: act only by rules you'd want EVERYONE to follow. The strength is that it protects individual rights absolutely — you can't sacrifice one person for the greater good. The weakness: what do you do when two duties conflict? 'Don't lie' vs 'protect the innocent' — Kant struggled with this.")
b('ph-021', 'Virtue Ethics', "Virtue ethics doesn't ask 'what should I DO?' — it asks 'what kind of person should I BE?' Instead of following rules or calculating outcomes, you develop good character traits (virtues) through practice. Aristotle identified virtues like courage, honesty, generosity, and justice. Each virtue is a balance: courage is between cowardice and recklessness. The appeal: it matches how we actually think about morality. We admire people for their character, not for being good calculators. The challenge: it doesn't give clear answers to specific dilemmas.")

// ph-023: Categorical Imperative
b('ph-023', 'Formula of Universal Law', "This is Kant's most famous test: before you act, ask 'what if everyone did this?' Want to lie to get out of trouble? Imagine a world where everyone lies — trust collapses, and lying becomes pointless because nobody believes anything. The rule contradicts itself when universalized. Want to break a promise? If everyone broke promises, the concept of promising would cease to exist. The test works by finding logical contradictions, not by predicting consequences. That's what makes it different from utilitarianism.")
b('ph-023', 'Formula of Humanity', "Kant's second formulation hits differently: never treat people MERELY as means to your end. You can hire someone (using them as a means) as long as you also respect their dignity, pay them fairly, and treat them as a person with their own goals. But manipulating someone, deceiving them, or exploiting their vulnerability treats them as a tool — that's always wrong. This principle is the philosophical foundation of human rights, informed consent in medicine, and labor protections. It says every person has inherent worth that can't be traded away.")
b('ph-023', 'Kingdom of Ends', "The third formulation asks you to imagine a community where everyone is both a lawmaker and a subject. Every rule you propose, you must also follow. Every person affected by the rule has a voice. This is Kant's vision of an ideal moral community — not a democracy exactly, but a community of mutual respect where no one is above the rules. It's remarkably close to John Rawls's 'veil of ignorance' idea 200 years later. The practical takeaway: don't make exceptions for yourself.")

// ph-024: Trolley Problem variants
b('ph-024', 'Classic Trolley', "Philippa Foot introduced this in 1967, and it became the most discussed thought experiment in modern ethics. The setup is simple: trolley heading toward five people, you can pull a lever to divert it to a track with one person. About 90% of people say pull the lever. The reasoning seems straightforward: five lives outweigh one. But this intuition — that you should actively cause one death to prevent five — has surprising implications. It suggests most people are at least somewhat utilitarian in their moral thinking.")
b('ph-024', 'Footbridge', "Judith Jarvis Thomson added this variant: you're on a bridge above the tracks. A large man is next to you. If you push him onto the tracks, his body will stop the trolley, saving five people. Same math as before — one death to save five. But about 90% of people say DON'T push. Why? The physical act of pushing someone to their death feels fundamentally different from pulling a lever, even though the outcome is identical. This gap between our moral intuitions and utilitarian logic is what makes the trolley problem so powerful.")
b('ph-024', 'The Puzzle', "The puzzle isn't about trolleys — it's about YOU. If you'd pull the lever but not push the man, your moral reasoning is inconsistent. A pure utilitarian would do both (same outcome). A pure deontologist might do neither (you're causing a death either way). But most people split: lever yes, push no. This suggests our moral psychology uses MULTIPLE frameworks simultaneously — we care about outcomes AND about the nature of our actions AND about physical directness. Understanding this inconsistency is the first step toward more reflective moral thinking.")
b('ph-024', 'What It Reveals', "The trolley problem has real-world applications that go far beyond philosophy classrooms. Self-driving car programmers must decide: should the car swerve to save passengers at the risk of hitting pedestrians? Doctors face triage decisions: which patient gets the last ventilator? Military commanders weigh civilian casualties against strategic objectives. In each case, the trolley problem's core tension — between maximizing lives saved and respecting individual rights — is exactly what decision-makers face.")

// ph-025: Moral relativism vs objectivism
b('ph-025', 'Moral Objectivism', "Moral objectivism says some things are wrong regardless of what anyone thinks. Slavery was wrong in ancient Rome even though Romans accepted it. The Holocaust was wrong even though Nazi ideology endorsed it. The appeal is powerful: without objective morality, you can't criticize any culture's practices. But the challenge is equally powerful: WHERE do these objective moral truths come from? God? Human nature? Reason? Each answer has problems. And how do you explain the massive moral disagreement across cultures if there's one objective truth?")
b('ph-025', 'Moral Relativism', "Moral relativism says morality is determined by cultural norms — there's no view from nowhere, no culture-independent standard. What's 'right' in one society may be 'wrong' in another, and neither is objectively correct. This sounds tolerant, but it has a dark side: if morality is purely cultural, you can't say slavery was wrong in cultures that accepted it. You can't criticize female genital mutilation in cultures that practice it. Most people who call themselves relativists don't actually accept these implications.")
b('ph-025', 'Cultural Relativism', "Cultural relativism is often confused with moral relativism, but it's actually a descriptive claim, not a normative one. It simply observes: different cultures DO have different moral beliefs. Some cultures practice polygamy, others don't. Some consider eating insects normal, others find it disgusting. This is just a fact about the world. The philosophical leap — from 'cultures disagree about morality' to 'therefore no culture is right' — is called the 'diversity argument,' and most philosophers consider it a logical fallacy. Disagreement doesn't prove there's no truth.")

// ph-026: Rights
b('ph-026', 'Negative Rights', "Negative rights are 'leave me alone' rights. Freedom of speech means the government can't stop you from speaking — it doesn't mean anyone has to give you a microphone or an audience. The right to life means nobody can kill you — it doesn't mean someone must feed you. These rights are 'negative' because they require others to NOT do something. Libertarians tend to emphasize negative rights because they require minimal government: just prevent people from harming each other, and otherwise stay out of the way.")
b('ph-026', 'Positive Rights', "Positive rights are 'give me something' rights. The right to education means someone must provide schools and teachers. The right to healthcare means someone must provide medical treatment. These rights require active provision, which means someone has to pay for them — usually through taxes. This is where political disagreements get heated: if healthcare is a right, can the government force doctors to work? Can it force taxpayers to fund it? Positive rights create obligations on others in a way negative rights don't.")
b('ph-026', 'Natural Rights', "John Locke argued that certain rights exist BEFORE any government — life, liberty, and property. You have them simply by being human, not because any law grants them. Government's job is to PROTECT these pre-existing rights, not to create them. This idea was revolutionary: it meant a government that violates natural rights is illegitimate, and people can overthrow it. Thomas Jefferson borrowed this directly for the Declaration of Independence: 'We hold these truths to be self-evident, that all men are created equal, endowed with certain unalienable rights.'")

// ph-029: Virtue Ethics in depth
b('ph-029', 'Eudaimonia', "Eudaimonia is often translated as 'happiness,' but that's misleading. It's closer to 'flourishing' or 'living well and doing well.' Aristotle didn't mean feeling good — he meant living a complete, excellent human life. A person with eudaimonia has good character, meaningful relationships, engages in worthwhile activities, and has enough external goods (health, friends, some wealth) to exercise their virtues. You can't achieve eudaimonia in a single moment — it's a judgment about your whole life, like saying 'she lived well.'")
b('ph-029', 'Golden Mean', "The golden mean is Aristotle's insight that every virtue sits between two vices — one of excess and one of deficiency. Courage is between cowardice (too little) and recklessness (too much). Generosity is between stinginess and wastefulness. Honesty is between secretiveness and oversharing. The mean isn't a mathematical midpoint — it depends on the situation. A soldier needs more courage than an accountant. Finding the right balance in each specific context is what Aristotle called practical wisdom.")
b('ph-029', 'Practical Wisdom', "Phronesis (practical wisdom) is the master virtue in Aristotle's system — without it, you can't exercise any other virtue well. It's the ability to perceive what a situation requires and respond appropriately. Rules can't capture it: 'always be honest' doesn't tell you HOW honest to be with a grieving friend. Practical wisdom is knowing when to speak and when to stay silent, when to be firm and when to be gentle. You develop it through experience, mentorship, and reflection — not from reading a textbook. It's why Aristotle said ethics can't be learned by the young.")
b('ph-029', 'Habituation', "Aristotle's most practical insight: you become virtuous by PRACTICING virtue, not by thinking about it. You don't become courageous by reading about courage — you become courageous by doing courageous things, starting small. Each act of courage makes the next one easier until it becomes second nature. This is remarkably similar to modern psychology's understanding of habit formation. It also means character education matters: the habits you form in childhood shape who you become. Aristotle would have loved the '10,000 hours' concept.")

// ============================================================
// PHILOSOPHY — argumentation
// ============================================================

// ph-042: Argument anatomy
b('ph-042', 'Premise', "Think of premises as the foundation of a building — the conclusion sits on top. If the foundation is shaky, the whole structure collapses. In everyday arguments, premises are often unstated. 'You should carry an umbrella' has a hidden premise: 'it's going to rain.' Skilled arguers learn to surface these hidden premises because that's usually where arguments are weakest. Next time someone makes a claim, ask: 'what are you assuming is true?'")
b('ph-042', 'Conclusion', "The conclusion is the destination of the argument — where all the premises are trying to take you. In academic writing, it's usually stated explicitly. In everyday conversation, it's often implied. 'The restaurant has a C health rating and my friend got sick there' — the unstated conclusion is 'don't eat there.' Tip for evaluating arguments: identify the conclusion first, then work backward to find the premises. This prevents you from getting lost in the details.")
b('ph-042', 'Valid', "Validity is about STRUCTURE, not truth. 'All fish can fly. My cat is a fish. Therefore my cat can fly.' This argument is perfectly VALID — the conclusion follows logically from the premises. It's just not SOUND because the premises are false. This distinction matters because it separates two different ways an argument can fail: bad logic (invalid) vs. false claims (unsound). You can have true premises and a true conclusion but still be invalid if the logic doesn't connect them properly.")
b('ph-042', 'Sound', "A sound argument is the gold standard: it's valid (the logic works) AND all premises are actually true. 'All humans need oxygen. You are human. Therefore you need oxygen.' Valid structure + true premises = guaranteed true conclusion. In practice, most real-world arguments are hard to prove sound because premises are debatable. 'Democracy is the best system' — is that premise true? Depends on what 'best' means. Recognizing that most arguments are valid-but-debatably-sound is a major step in critical thinking.")

// ph-043: Fallacies set 1
b('ph-043', 'Ad Hominem', "Ad hominem means 'against the person.' Instead of addressing someone's argument, you attack their character, motives, or background. 'You can't trust his opinion on climate change — he's funded by oil companies.' The funding IS relevant context, but it doesn't make his argument wrong. Even biased people can make valid arguments. The proper response is to evaluate the argument on its merits, then consider the source as additional context. Politicians use ad hominem constantly because it's emotionally effective even when logically irrelevant.")
b('ph-043', 'Straw Man', "A straw man is easier to knock down than a real opponent — that's the metaphor. You misrepresent someone's position to make it easier to attack. 'I think we should have some gun regulations.' 'So you want to ban ALL guns and leave people defenseless!' The second person isn't responding to the actual argument — they've built a weaker version and attacked that instead. Straw men are everywhere in political debate. The antidote: before criticizing a position, restate it in the strongest form the other person would accept.")
b('ph-043', 'Appeal to Authority', "Not all appeals to authority are fallacious — citing a climate scientist on climate change is perfectly reasonable. The fallacy occurs when the authority isn't an expert in the relevant field. A famous actor endorsing a diet, a physicist opining on economics, a CEO giving medical advice — their fame or expertise in one area doesn't transfer. The key question: is this person an expert in THIS specific topic? Even legitimate experts can be wrong, which is why scientific consensus (many experts agreeing) is stronger than any individual authority.")
b('ph-043', 'Red Herring', "A red herring is a distraction — introducing an irrelevant topic to divert attention from the actual argument. 'Why should we worry about climate change when there are homeless people on our streets?' Homelessness is a real problem, but it has nothing to do with whether climate change is real or requires action. Red herrings work because the new topic is often emotionally compelling. The defense: always ask 'is this relevant to the original question?' If not, name it and redirect.")
b('ph-043', 'False Dilemma', "A false dilemma presents only two options when more exist. 'You're either with us or against us.' 'Either we ban all immigration or our culture will be destroyed.' Real life almost always has more than two options. The middle ground, the third way, the compromise — these are deliberately excluded to force you into a corner. Politicians love false dilemmas because they simplify complex issues into us-vs-them narratives. Whenever someone presents only two choices, ask: 'what are the other options they're not mentioning?'")

// ph-044: Fallacies set 2
b('ph-044', 'Slippery Slope', "The slippery slope argues that one small step will inevitably lead to extreme consequences. 'If we allow same-sex marriage, next people will want to marry animals.' Each step in the chain MIGHT follow, but the argument assumes they WILL follow without providing evidence for each link. Some slopes are genuinely slippery (addiction often does escalate), but the fallacy occurs when the chain of consequences is asserted without justification. The test: does each step actually follow from the previous one, or is it just fear-mongering?")
b('ph-044', 'Circular Reasoning', "Circular reasoning uses the conclusion as one of its own premises — it goes in a circle. 'The Bible is true because it's the word of God, and we know it's the word of God because the Bible says so.' The argument assumes what it's trying to prove. A subtler example: 'Free markets are the best economic system because they allow maximum economic freedom.' That's just restating the conclusion in different words. Circular arguments can be hard to spot because they often use different phrasing for the same idea.")
b('ph-044', 'Appeal to Emotion', "This fallacy substitutes emotional manipulation for logical argument. A charity shows heartbreaking photos of suffering children instead of providing data about how effectively donations are used. A politician uses fear of terrorism to justify surveillance without showing it actually prevents attacks. Emotions aren't irrelevant to decision-making — but they should supplement evidence, not replace it. The test: remove the emotional content. Is there still a logical argument underneath? If not, it's pure manipulation.")
b('ph-044', 'Bandwagon', "The bandwagon fallacy assumes that popularity equals truth. 'Millions of people believe in astrology, so there must be something to it.' 'Everyone's investing in crypto, so it must be a good investment.' History is full of things millions of people believed that turned out to be wrong: the earth is flat, bloodletting cures disease, smoking is harmless. Truth isn't determined by vote. The bandwagon is especially dangerous in financial markets, where following the crowd can lead to bubbles and crashes.")
b('ph-044', 'Hasty Generalization', "A hasty generalization draws a broad conclusion from too few examples. 'I met two rude people from Paris, so Parisians are rude.' 'My grandfather smoked and lived to 95, so smoking isn't that bad.' The problem is sample size: a few examples can't represent an entire population. This fallacy is the engine of stereotyping — meeting a few members of a group and generalizing to all of them. The antidote: ask 'how many examples am I basing this on?' and 'could there be a selection bias in what I've observed?'")

// ============================================================
// PHILOSOPHY — critical thinking
// ============================================================

// ph-058: Assumptions
b('ph-058', 'Explicit Assumption', "An explicit assumption is one the arguer openly states: 'Assuming the economy stays stable, we should invest in stocks.' You can see it, evaluate it, and challenge it. Explicit assumptions are actually a sign of intellectual honesty — the arguer is telling you what they're taking for granted. Scientists do this constantly: 'assuming no air resistance,' 'assuming a spherical cow.' The assumptions simplify the problem, and stating them lets others know exactly where the argument might break down.")
b('ph-058', 'Implicit Assumption', "Implicit assumptions are the dangerous ones — they're beliefs the arguer takes for granted without even realizing it. 'We should teach coding in all schools' implicitly assumes: coding skills will remain valuable, schools are the right venue, current curriculum has room, all students benefit equally. None of these are obviously true, but they're never stated or defended. Finding implicit assumptions is like finding the invisible load-bearing walls in a building — remove one and the whole structure might collapse.")
b('ph-058', 'How to Find Them', "The best technique for finding hidden assumptions: ask 'what must be true for this conclusion to follow from these premises?' The gap between what's stated and what's concluded is filled by assumptions. Another technique: imagine someone from a completely different culture hearing the argument. What would they find puzzling or non-obvious? That puzzlement points to cultural assumptions you've internalized. A third technique: try to construct a counterexample. If you can imagine a scenario where the premises are true but the conclusion is false, there's a hidden assumption bridging the gap.")

// ph-059: Facts vs opinions
b('ph-059', 'Fact', "A fact is a statement that can be independently verified — checked by anyone using agreed-upon methods. 'Water boils at 100°C at sea level' is a fact: get a thermometer and test it. 'The population of Tokyo is about 14 million' is a fact: check census data. Facts can be wrong (outdated data, measurement error), but they're the kind of claim that HAS a definite answer. The key test: could two reasonable people, given the same evidence, agree on whether this is true?")
b('ph-059', 'Opinion', "An opinion is a personal judgment or preference that can't be proven true or false. 'Coffee tastes better than tea' is an opinion — there's no experiment that could settle it. 'Picasso is the greatest artist' is an opinion — 'greatest' depends on criteria that are themselves matters of opinion. Opinions aren't worthless — informed opinions backed by expertise and evidence are valuable. But they're different from facts, and treating opinions as facts (or demanding facts be treated as opinions) is a common source of confusion in public discourse.")
b('ph-059', 'Claim', "A claim is a statement that COULD be true or false but needs evidence to determine which. 'Exercise reduces depression' sounds factual, but it's actually a claim that requires research to verify. 'Immigration increases crime' is a claim — it might be true or false depending on the data. Claims are the most important category to recognize because they're often presented AS facts when they're actually unproven. The critical thinker's reflex: when someone states a claim as fact, ask 'what's the evidence?'")
b('ph-059', 'Informed Opinion', "An informed opinion sits between pure opinion and established fact. 'Based on current economic indicators, I believe inflation will decrease next year' is an informed opinion — it's a judgment, but it's grounded in evidence and expertise. A doctor's opinion about your treatment is more valuable than a random person's because it's informed by training and experience. The key: informed opinions should be transparent about their evidence and acknowledge uncertainty. 'I think X because of Y, but I could be wrong if Z' is the mark of intellectual honesty.")

// ph-060: Cognitive biases
b('ph-060', 'Confirmation Bias', "Confirmation bias is the mother of all biases — it affects everything. You don't just passively receive information; you actively seek out information that confirms what you already believe and ignore or dismiss contradicting evidence. Google 'is coffee healthy?' and you'll click the articles that say yes. Your brain literally processes confirming evidence faster and more favorably than disconfirming evidence. The scariest part: knowing about confirmation bias doesn't make you immune to it. The only defense is deliberately seeking out opposing viewpoints.")
b('ph-060', 'Anchoring', "The first number you hear disproportionately influences your judgment, even when it's completely irrelevant. In one famous study, people spun a random wheel showing either 10 or 65, then estimated the percentage of African countries in the UN. Those who saw 65 guessed much higher than those who saw 10 — even though the wheel was obviously random. Salespeople exploit this constantly: show the expensive option first, and the medium option seems reasonable. Real estate agents show overpriced houses first to make the target house seem like a deal.")
b('ph-060', 'Dunning-Kruger', "The Dunning-Kruger effect explains a frustrating pattern: beginners are often MORE confident than experts. After one week of guitar lessons, you might think 'I could play at an open mic.' After five years, you realize how much you still don't know. The effect occurs because evaluating your own competence requires the same skills as the competence itself. If you don't know much about a topic, you also don't know enough to recognize your own ignorance. The antidote: the more confident you feel about something you recently learned, the more skeptical you should be of that confidence.")
b('ph-060', 'Availability Heuristic', "Your brain judges probability by how easily examples come to mind, not by actual statistics. Plane crashes are vivid and memorable, so people overestimate the risk of flying (1 in 11 million) while underestimating the risk of driving (1 in 5,000). Shark attacks make the news; falling coconuts don't — yet coconuts kill more people annually. Media coverage amplifies this: whatever gets reported feels common. After a school shooting, parents overestimate the risk to their children, even though schools are statistically very safe. The fix: always check the actual numbers before trusting your gut feeling about risk.")

// ph-062: Source evaluation
b('ph-062', 'Expertise', "Not all experts are equal, and expertise doesn't transfer across fields. A Nobel Prize-winning physicist isn't an authority on nutrition. A successful CEO isn't an authority on epidemiology. Yet media constantly presents famous people as experts on topics outside their field. The key questions: does this person have formal training in THIS specific area? Have they published peer-reviewed research on THIS topic? Do other experts in the field respect their work? A surgeon's opinion on heart surgery matters; their opinion on climate policy doesn't carry special weight.")
b('ph-062', 'Evidence', "Evidence comes in a hierarchy of reliability. At the top: systematic reviews and meta-analyses (combining many studies). Then: randomized controlled trials. Then: observational studies. Then: case reports. At the bottom: anecdotes and personal experience. 'My uncle took this supplement and his cancer went away' is the weakest form of evidence — it could be coincidence, placebo, or misdiagnosis. When evaluating a claim, ask: what KIND of evidence supports it? A single study is interesting; a meta-analysis of 50 studies is convincing.")
b('ph-062', 'Bias', "Every source has potential biases — the question is whether those biases affect the conclusions. A study funded by a pharmaceutical company finding their drug works should be scrutinized more carefully than an independent study finding the same thing. A news outlet owned by a political party will frame stories differently than an independent outlet. Bias doesn't automatically make something wrong — but it means you should look for corroboration from sources with DIFFERENT biases. If a left-leaning and right-leaning outlet agree on a fact, it's probably reliable.")
b('ph-062', 'Consensus', "Scientific consensus isn't just 'most scientists agree' — it's the result of thousands of researchers independently testing, replicating, and challenging each other's work over years or decades. When 97% of climate scientists agree on human-caused climate change, that's not groupthink — it's the result of overwhelming evidence surviving intense scrutiny. Outlier claims aren't automatically wrong, but they need proportionally stronger evidence. As Carl Sagan said: 'Extraordinary claims require extraordinary evidence.' One contrarian study doesn't overturn a consensus built on thousands.")

// ============================================================
// PHILOSOPHY — applied philosophy
// ============================================================

// ph-074: Stoic Dichotomy of Control
b('ph-074', 'What You Control', "Epictetus, a former slave who became one of Stoicism's greatest teachers, made this the foundation of his philosophy. You control your judgments, your desires, your effort, and your responses. That's it. You don't control whether you get the job — you control how well you prepare. You don't control whether someone likes you — you control how you treat them. This isn't passive acceptance; it's strategic focus. By directing all your energy toward what you can actually influence, you become both calmer and more effective.")
b('ph-074', "What You Don't Control", "The list of things outside your control is humbling: other people's opinions, the weather, the economy, traffic, your boss's mood, whether your flight is delayed, whether your startup succeeds. Even your own body is partly outside your control — you can exercise and eat well, but you can't guarantee health. The Stoic insight: suffering comes not from these events but from your JUDGMENT about them. Rain isn't bad — your opinion that rain is bad causes frustration. Change the judgment, and the suffering dissolves.")
b('ph-074', 'The Practice', "The daily practice is simple but hard: when you feel stressed, angry, or anxious, pause and ask 'is this within my control?' If yes, take action. If no, consciously release it. Marcus Aurelius did this while running the Roman Empire during a plague. Epictetus did it while enslaved. The practice doesn't require special conditions — it works in traffic, in meetings, in arguments with family. Start small: next time you're frustrated by a delayed train, notice the frustration, ask the question, and redirect your attention to something you CAN do (read, think, plan).")
b('ph-074', 'Marcus Aurelius', "Marcus Aurelius was the most powerful man in the world — Roman Emperor from 161 to 180 AD — and he spent his evenings writing private notes to himself about how to be a better person. His Meditations was never meant to be published; it's literally a journal of self-improvement. He reminds himself to be patient with annoying people, to not be seduced by luxury, to remember he'll die someday. The fact that an emperor with absolute power chose to practice humility and self-discipline is what makes Stoicism so compelling. If it worked for him, it can work for anyone.")

// ph-075: Existentialist authenticity
b('ph-075', 'Authenticity', "Authenticity in existentialism doesn't mean 'being yourself' in the Instagram sense. It means honestly confronting your freedom, making deliberate choices, and taking full responsibility for your life. An authentic person doesn't hide behind social roles ('I'm just doing my job'), cultural expectations ('that's how things are done'), or excuses ('I had no choice'). They acknowledge that every moment involves a choice — even choosing to do nothing is a choice. Authenticity is uncomfortable because it removes all the comfortable excuses we use to avoid responsibility.")
b('ph-075', 'Bad Faith', "Sartre's concept of 'bad faith' (mauvaise foi) is one of existentialism's most useful ideas. It's the act of deceiving yourself about your own freedom. The waiter who performs his role so perfectly that he forgets he's a person making choices. The employee who says 'I HAVE to stay in this job' when they mean 'I'm AFRAID to leave.' The person who says 'that's just who I am' to avoid changing. Bad faith is comfortable because it removes responsibility. Recognizing it in yourself is the first step toward authenticity — and it's deeply uncomfortable.")
b('ph-075', 'Radical Freedom', "Sartre argued that you are 'condemned to be free.' Even in prison, you choose how to respond to imprisonment. Even under threat, you choose whether to comply or resist. This sounds extreme, but Sartre lived through Nazi occupation of France and saw people make genuine choices under extreme pressure — some collaborated, some resisted, some did nothing. Each was a choice. The weight of this freedom is what Sartre called 'anguish' — the dizzying realization that nothing determines your path except you. Most people flee from this anguish into bad faith.")
b('ph-075', 'Responsibility', "If you're radically free, you're radically responsible. You can't blame your parents for your personality — you choose how to respond to your upbringing. You can't blame society for your conformity — you choose whether to conform. You can't even blame your emotions — you choose how to act on them. Sartre went further: you're responsible not just for yourself but for the image of humanity you project. When you choose to lie, you're choosing a world where lying is acceptable. Every personal choice is also a statement about what humans should be.")

// ph-076: Death
b('ph-076', 'Memento Mori', "Roman generals celebrating military triumphs had a slave stand behind them whispering 'memento mori' — remember, you will die. It wasn't meant to depress them but to keep them grounded amid glory. The Stoics adopted this as a daily practice: each morning, remind yourself that today could be your last. The effect isn't morbid — it's clarifying. That petty argument? Not worth your limited time. That dream you keep postponing? Start today. Steve Jobs said his daily memento mori practice ('If today were the last day of my life, would I want to do what I'm about to do?') was his most important decision-making tool.")
b('ph-076', 'Seneca', "Seneca was a Roman Stoic philosopher, playwright, and advisor to Emperor Nero. His most famous essay, 'On the Shortness of Life,' argues that life isn't actually short — we just waste most of it. We spend years chasing status, worrying about things we can't control, and postponing what matters. 'It is not that we have a short time to live, but that we waste a great deal of it.' His practical advice: audit your time. How much goes to meaningful work, relationships, and growth? How much goes to distraction, anxiety, and obligation? The gap reveals your real priorities.")
b('ph-076', 'Epicurus', "Epicurus offered the most logically airtight argument against fearing death: 'Where death is, I am not. Where I am, death is not.' You will never experience being dead — death is the absence of experience. Fearing death is like fearing the time before you were born. Were you distressed about not existing in 1750? No. Non-existence after death is the same. This argument doesn't address the fear of the PROCESS of dying (which is about pain, not death) or the grief of those left behind. But for the fear of death itself — of not existing — Epicurus's logic is hard to refute.")
b('ph-076', 'Heidegger', "Heidegger argued that most people live in denial of death — they know intellectually that they'll die but don't truly FEEL it. They treat death as something that happens to other people. But when you genuinely confront your own mortality — through illness, a close call, or deep reflection — everything changes. Suddenly, time becomes precious. Trivial concerns fall away. Authentic priorities emerge. Heidegger called this 'being-toward-death': living with genuine awareness of your finitude. It's not depressing — it's the precondition for living authentically.")

// ph-078: Nietzsche
b('ph-078', 'Amor Fati', "Amor fati — love of fate — is Nietzsche's most life-affirming idea. Don't just tolerate what happens to you; LOVE it. That painful breakup? It made you who you are. That career failure? It redirected you somewhere better. The key insight: you can't love the good parts of your life while rejecting the bad parts, because they're inseparable. Every joy was made possible by prior suffering. Nietzsche wrote: 'My formula for greatness in a human being is amor fati: that one wants nothing to be different, not forward, not backward, not in all eternity.'")
b('ph-078', 'Eternal Recurrence', "Imagine a demon tells you: you will live this exact life — every joy, every pain, every boring Tuesday — infinitely on repeat. Nothing changes. Would you scream in despair or say 'yes, again!'? Nietzsche designed this as the ultimate test of how you're living. If the thought horrifies you, something needs to change. If you can embrace it, you're living authentically. It's not meant as a literal cosmological theory — it's a thought experiment that forces radical honesty about whether your life is one you'd choose.")
b('ph-078', 'The Test', "The eternal recurrence works as a daily decision-making tool. Before any choice, ask: 'Would I want to make this choice infinite times?' Staying in a job you hate? Would you choose that forever? Spending Sunday scrolling your phone? Would you relive that endlessly? The test cuts through rationalization and reveals what you actually value versus what you merely tolerate. It's Nietzsche's version of memento mori — but instead of 'you will die,' it's 'you will live THIS, forever.' Both push you toward the same thing: living deliberately.")
b('ph-078', 'Will to Power', "The 'will to power' is Nietzsche's most misunderstood concept, largely because the Nazis hijacked it. It has nothing to do with dominating others. Nietzsche meant the fundamental human drive to overcome yourself — to grow, create, and become more than you are. An artist's will to power is creating a masterpiece. A scientist's is making a discovery. An athlete's is breaking their personal record. It's the drive toward self-overcoming, not domination. Nietzsche despised nationalism and anti-Semitism — he would have been horrified by how the Nazis used his work.")

// ph-079: Buddhism
b('ph-079', '1. Dukkha', "The First Noble Truth is often translated as 'life is suffering,' but that's too bleak. Dukkha is closer to 'unsatisfactoriness' or 'pervasive dissatisfaction.' Even good experiences contain dukkha because they're impermanent — the delicious meal ends, the vacation is over, the person you love will eventually die or leave. It's not that life is ONLY suffering; it's that even pleasure is tinged with the anxiety of its passing. This isn't pessimism — it's a clear-eyed diagnosis, like a doctor identifying a disease before prescribing treatment.")
b('ph-079', '2. Samudaya', "The Second Noble Truth identifies the CAUSE of suffering: tanha, usually translated as 'craving' or 'attachment.' You suffer not because of what happens, but because you crave things to be different from how they are. You want the pleasure to last forever. You want the pain to stop immediately. You want people to behave as you wish. This constant grasping — wanting what you don't have, wanting to keep what you do have, wanting to avoid what you fear — is the engine of suffering. The craving itself is the problem, not the object of craving.")
b('ph-079', '3. Nirodha', "The Third Noble Truth is the good news: suffering CAN end. Not by getting everything you want (that's impossible and wouldn't work anyway — you'd just want more), but by releasing attachment to specific outcomes. This doesn't mean becoming emotionless or not caring. It means holding your desires lightly — wanting things without NEEDING them, preferring outcomes without being devastated when they don't happen. The Buddhist term is 'nirvana,' which literally means 'blowing out' — extinguishing the flames of craving.")
b('ph-079', '4. Magga', "The Fourth Noble Truth is the practical path: the Noble Eightfold Path. It's not a set of commandments but a training program for the mind. Right understanding and right intention (wisdom). Right speech, right action, right livelihood (ethical conduct). Right effort, right mindfulness, right concentration (mental discipline). 'Right' here doesn't mean morally correct — it means 'skillful' or 'conducive to awakening.' The path isn't linear; you practice all eight aspects simultaneously, each supporting the others. Meditation is the training ground, but the real practice is how you live.")

// Remaining philosophy structured_list tasks
// ph-094: Aesthetics
b('ph-094', 'Aesthetics', "Aesthetics is philosophy's attempt to understand beauty, art, and taste. Why does a sunset move you? Why do some songs make you cry? Is beauty 'in the eye of the beholder' or is there something objectively beautiful about a perfectly proportioned face or a Bach fugue? Plato thought beauty was objective — beautiful things participate in the Form of Beauty. Hume thought it was subjective but that educated taste converges. The debate continues: is there a difference between 'I like it' and 'it's good'?")
b('ph-094', 'Kant on Beauty', "Kant made a subtle distinction: when you call something beautiful, you're not just reporting a personal preference (like 'I like chocolate'). You're making a claim that OTHERS should agree. 'This sunset is beautiful' feels different from 'I enjoy this sunset.' Kant called this 'subjective universality' — beauty is felt subjectively but claimed universally. This explains why we argue about art: if beauty were purely personal, disagreement would be pointless. But we DO argue, which suggests we believe beauty is more than just preference.")
b('ph-094', 'Tolstoy on Art', "Tolstoy rejected the idea that art is about beauty or technique. In 'What Is Art?' he argued that real art is the transmission of genuine feeling from artist to audience. A peasant song that makes you feel the singer's joy is better art than a technically perfect opera that leaves you cold. This was radical: it meant most 'high art' wasn't really art at all, just skilled craftsmanship. Tolstoy's test: does the work infect you with the artist's emotion? If yes, it's art. If it just impresses you with technique, it's not.")

// ph-095: Philosophy of Language
b('ph-095', 'Wittgenstein', "Ludwig Wittgenstein is unique in philosophy: he published two major works that completely contradict each other. His early work (Tractatus) argued language pictures reality — each meaningful sentence corresponds to a possible state of affairs. His later work (Philosophical Investigations) demolished this view entirely. He realized meaning comes from USE, not from picturing. The word 'game' doesn't refer to one thing — board games, card games, video games, the Olympic Games share 'family resemblances' but no single definition. This insight revolutionized philosophy of language.")
b('ph-095', 'Sapir-Whorf', "The Sapir-Whorf hypothesis claims that the language you speak shapes how you think. The strong version (language DETERMINES thought) is mostly rejected — you can think about things you don't have words for. But the weak version (language INFLUENCES thought) has strong evidence. Russian speakers, who have separate words for light blue and dark blue, are faster at distinguishing those colors. The Hopi language structures time differently than English, which may affect how Hopi speakers think about time. Your language doesn't imprison your thoughts, but it does create well-worn paths that are easier to follow.")
b('ph-095', 'Performative Speech', "J.L. Austin noticed that some sentences don't describe reality — they CHANGE it. 'I promise to pay you back' creates an obligation that didn't exist before. 'I now pronounce you married' changes two people's legal status. 'You're fired' ends an employment relationship. Austin called these 'performative utterances' — they perform an action rather than stating a fact. This insight matters because it shows language isn't just a mirror of reality; it's a tool that shapes social reality. Laws, contracts, and institutions are all built from performative speech acts.")

// ph-099: Autonomy and consent
b('ph-099', 'Autonomy', "Autonomy literally means 'self-rule' — the right to make your own decisions about your own life, even bad ones. It's the philosophical foundation of informed consent in medicine, freedom of religion, and the right to refuse treatment. The key tension: where does your autonomy end and someone else's begin? Mill's answer: your autonomy extends until it harms others. But 'harm' is debatable — does secondhand smoke count? Does offensive speech? Does refusing to vaccinate? These boundary cases are where autonomy gets philosophically interesting.")
b('ph-099', 'Paternalism', "Paternalism is when someone overrides your choices 'for your own good' — like a parent deciding for a child. Seatbelt laws are paternalistic: the government forces you to protect yourself. Banning recreational drugs is paternalistic: the state decides you can't take that risk. The philosophical question: when is paternalism justified? Most people accept it for children and people with severe mental illness. But for competent adults? Libertarians say almost never. Others argue that cognitive biases (we're bad at assessing risk) sometimes justify gentle paternalism — 'nudges' that steer behavior without removing choice.")
b('ph-099', 'Informed Consent', "Informed consent is one of philosophy's most important practical contributions. It emerged from horrific medical experiments (Nazi doctors, the Tuskegee syphilis study) where people were used as research subjects without their knowledge or agreement. The principle: you can only consent to something if you understand what you're agreeing to — the risks, alternatives, and consequences. This applies beyond medicine: terms of service you don't read, financial products you don't understand, data collection you're not aware of. True consent requires genuine understanding, not just a signature.")

// ph-103: Modus Ponens/Tollens
b('ph-103', 'Modus Ponens', "Modus ponens is the most basic valid argument form, and you use it dozens of times daily without realizing it. 'If it's raining, the ground is wet. It's raining. Therefore the ground is wet.' The structure: If P then Q. P is true. Therefore Q. It's so intuitive it seems trivial, but it's the building block of all deductive reasoning. Every mathematical proof, every legal argument, every scientific prediction uses chains of modus ponens. Recognizing it helps you see the logical skeleton beneath everyday arguments.")
b('ph-103', 'Modus Tollens', "Modus tollens works backward from a false consequence. 'If it rained, the ground would be wet. The ground is dry. Therefore it didn't rain.' The structure: If P then Q. Not Q. Therefore not P. This is how scientists disprove hypotheses: 'If this theory is correct, we should observe X. We don't observe X. Therefore the theory is wrong.' Karl Popper argued that all of science works by modus tollens — you can never prove a theory true, only prove it false by finding predictions that don't hold up.")
b('ph-103', 'Invalid: Affirming Consequent', "This is the most common logical error, and it's seductive because it FEELS valid. 'If it rains, the ground is wet. The ground is wet. Therefore it rained.' But wait — sprinklers could have caused the wet ground! The structure: If P then Q. Q is true. Therefore P. This is INVALID because Q could be true for reasons other than P. Real-world example: 'If someone is a criminal, they avoid eye contact. He's avoiding eye contact. Therefore he's a criminal.' Obviously wrong — shyness, cultural norms, and autism also cause eye contact avoidance.")

// ph-108: Sunk Cost
b('ph-108', 'Sunk Cost Fallacy', "The sunk cost fallacy is one of the most expensive cognitive errors humans make. You've read 200 pages of a terrible book, so you finish it ('I've already invested so much'). You've been in a bad relationship for 3 years, so you stay ('I can't waste those years'). A company has spent $50 million on a failing project, so they spend $50 million more ('we can't write off the investment'). The fallacy: past costs are gone regardless of what you do next. The only rational question is: 'From this point forward, what's the best use of my time/money?'")
b('ph-108', 'Why It Happens', "The sunk cost fallacy persists because of loss aversion — we feel losses about twice as strongly as equivalent gains. Abandoning a project feels like LOSING the time and money already spent, even though that time and money are gone either way. There's also an identity component: admitting a sunk cost means admitting you made a bad decision, which threatens your self-image as a smart person. Organizations are especially vulnerable because nobody wants to be the person who 'wasted' the company's investment by pulling the plug.")
b('ph-108', 'The Fix', "The antidote to sunk cost thinking is a simple question: 'Knowing what I know now, would I START this today?' If you wouldn't begin reading this book today, stop reading it — regardless of how far you've gotten. If you wouldn't take this job today, start looking for a new one — regardless of how long you've been there. Warren Buffett applies this to investments: 'When you find yourself in a hole, stop digging.' The past is a sunk cost. The only costs that matter for decisions are future ones.")

// ph-119: Bentham vs Mill
b('ph-119', 'Bentham', "Jeremy Bentham was a radical egalitarian: he believed all pleasure is equal. The pleasure of playing a simple game (he used 'pushpin,' a children's game) is just as valuable as the pleasure of reading poetry — IF it produces the same amount of happiness. What matters is quantity: intensity, duration, certainty, and how many people are affected. Bentham even designed a 'felicific calculus' — a mathematical formula for calculating happiness. Critics found this absurd: surely the pleasure of intellectual discovery is WORTH more than the pleasure of eating candy?")
b('ph-119', 'Mill', "John Stuart Mill, Bentham's godson, agreed that happiness is the ultimate good but insisted that some pleasures are qualitatively BETTER than others. 'It is better to be Socrates dissatisfied than a fool satisfied.' His test: ask someone who has experienced BOTH intellectual and bodily pleasures which they prefer. Mill believed competent judges would always choose the 'higher' pleasure. This solved the 'pushpin vs poetry' problem but created a new one: who decides which pleasures are 'higher'? Isn't that just intellectual snobbery?")
b('ph-119', 'The Test', "Mill's 'competent judges' test is both elegant and problematic. The idea: only someone who has experienced both pleasures can compare them. A person who has read great literature AND played video games is qualified to judge which is more valuable. Someone who has only done one isn't. The appeal: it avoids pure subjectivism without imposing arbitrary rankings. The problem: competent judges might be biased toward whatever they were trained to value. A literature professor might rank reading higher simply because their identity is built around it, not because it's objectively superior.")

// ph-120: Harm Principle
b('ph-120', 'Harm Principle', "Mill's harm principle is the philosophical foundation of liberal democracy: the only legitimate reason to restrict someone's freedom is to prevent harm to OTHERS. Not to prevent self-harm, not to enforce morality, not to protect feelings. If you want to ride a motorcycle without a helmet, that's your right — you're only risking yourself. If you want to drink yourself to death, that's tragic but not the government's business. This principle sounds simple but generates endless debate: what counts as 'harm'? Is secondhand smoke harm? Is hate speech harm? Is economic exploitation harm?")
b('ph-120', 'Implication', "The harm principle has radical implications that many people who claim to support 'freedom' don't actually accept. If harm to others is the only justification for laws, then drug prohibition is unjustified (drug use primarily harms the user), prostitution between consenting adults should be legal, and suicide should be a legal right. Mill would say: educate people about risks, provide support services, but don't use the law to override their choices. Many societies that claim to value liberty still enforce paternalistic laws — the gap between stated values and actual policy is revealing.")
b('ph-120', 'Hard Case', "The hardest cases for the harm principle involve offense vs. harm. Someone burns a flag in front of veterans — deeply offensive but arguably not harmful. Someone publishes a cartoon mocking a religion — offensive to millions but no physical harm. Mill drew a firm line: offense is NOT harm. Being offended doesn't give you the right to silence someone. This position is increasingly controversial in an era of social media, where offensive speech can go viral and cause real psychological distress. The question remains: should we expand 'harm' to include severe emotional distress, or does that open the door to censoring any unpopular opinion?")

// ph-126: Toulmin Model
b('ph-126', 'Claim', "In the Toulmin model, the claim is what you're trying to get your audience to accept. It's equivalent to the conclusion in formal logic, but Toulmin's framework is designed for real-world arguments where certainty is rare. Claims can be factual ('smoking causes cancer'), policy-based ('we should raise the minimum wage'), or value-based ('privacy is more important than security'). The key insight: different types of claims require different types of evidence. A factual claim needs data; a value claim needs philosophical argument.")
b('ph-126', 'Evidence', "Toulmin called this 'data' or 'grounds' — the facts, statistics, examples, or testimony that support your claim. 'We should raise the minimum wage' needs evidence like: current minimum wage workers can't afford rent, studies show modest increases don't reduce employment, other countries with higher minimums have lower poverty. The evidence must be relevant (connected to the claim), sufficient (enough to be convincing), and accurate (factually correct). One anecdote isn't enough; cherry-picked statistics aren't honest.")
b('ph-126', 'Warrant', "The warrant is Toulmin's most original contribution — it's the unstated principle that connects evidence to claim. Evidence: 'Minimum wage workers can't afford rent.' Claim: 'We should raise the minimum wage.' Warrant (unstated): 'Society should ensure full-time workers can afford basic needs.' The warrant is often the most debatable part of an argument, yet it's usually left implicit. A libertarian might reject the warrant entirely: 'It's not society's job to guarantee affordability.' Finding and challenging warrants is the most powerful way to engage with real-world arguments.")
b('ph-126', 'Qualifier', "Qualifiers are what separate honest arguments from propaganda. Instead of 'this WILL work,' an honest arguer says 'this will PROBABLY work' or 'in most cases' or 'based on current evidence.' Qualifiers acknowledge uncertainty and limit the scope of the claim. 'Raising the minimum wage will likely reduce poverty for most workers, though some small businesses may reduce hiring.' Compare that to: 'Raising the minimum wage will destroy the economy.' The qualified version is less dramatic but more honest — and ultimately more persuasive to thoughtful audiences.")

// ph-129: Occam's Razor
b('ph-129', "Occam's Razor", "William of Ockham, a 14th-century friar, proposed a principle that became one of science's most important tools: don't multiply entities beyond necessity. If two explanations account for the same evidence, prefer the simpler one. Your keys are missing — Explanation A: you misplaced them. Explanation B: a burglar broke in, took only your keys, and left everything else. Both explain the missing keys, but A requires fewer assumptions. Occam's Razor doesn't prove A is correct — but it's the rational starting point.")
b('ph-129', 'Example', "Occam's Razor is the reason scientists prefer natural explanations over supernatural ones. Crop circles: Explanation A: people with boards and rope made them at night (documented many times). Explanation B: aliens traveled light-years to flatten wheat in geometric patterns. Both 'explain' the circles, but A requires far fewer assumptions. In medicine: your headache is probably from dehydration or tension, not a brain tumor. Start with the simplest explanation and only add complexity when the evidence demands it.")
b('ph-129', 'Limitation', "Occam's Razor is a guide, not a law. Sometimes reality IS complex. Quantum mechanics is far more complicated than classical physics, but it's correct. The germ theory of disease was more complex than 'bad air' (miasma theory), but it was right. The razor says: don't add complexity WITHOUT reason. If the simple explanation doesn't fit the evidence, you MUST consider more complex ones. Einstein reportedly said: 'Everything should be made as simple as possible, but not simpler.' The razor cuts away unnecessary complexity — it doesn't demand oversimplification.")

// ============================================================
// LEARN KANNADA — vocabulary & grammar
// ============================================================

// kn-007: Numbers 1-10
b('kn-007', '೧ ಒಂದು', "Pronounced ON-du with stress on the first syllable. The 'on' sounds like 'fund' without the 'f'. This is the most common number you'll use — ordering 'ondu coffee' (one coffee) at a darshini (quick-service restaurant). Kannada numerals (೧) are used on bus route numbers and price tags, so recognizing them helps in daily life.")
b('kn-007', '೨ ಎರಡು', "Pronounced EH-ra-du, three syllables. The 'r' is a soft tap, not the hard English 'r'. You'll hear this constantly in bargaining: 'eradu hundred' (two hundred). Memory aid: 'era' sounds like 'era' in English — think 'two eras of history.'")
b('kn-007', '೩ ಮೂರು', "Pronounced MOO-ru, like 'moo' (cow sound) + 'ru'. The long 'oo' is important — 'muru' (short) means something different. Used in the common phrase 'mooru dina' (three days). Kannada loves the number three — many folk sayings come in threes.")
b('kn-007', '೪ ನಾಲ್ಕು', "Pronounced NAAL-ku. The 'aa' is long, like 'father'. The 'lk' combination is tricky for English speakers — practice saying 'silk' and isolating the 'lk' sound. Memory aid: 'NAAL' sounds like 'null' — four letters in 'null.'")
b('kn-007', '೫ ಐದು', "Pronounced EYE-du, like the English word 'eye' + 'du'. One of the easiest numbers to remember because of the English connection. 'Aidu nimisha' (five minutes) is a phrase you'll hear constantly — it usually means 'sometime between 5 and 30 minutes.'")
b('kn-007', '೬ ಆರು', "Pronounced AA-ru with a long 'aa' like 'father'. Don't confuse with 'aaru' meaning 'river' — same pronunciation, context makes it clear. Memory aid: 'AA-ru' has two syllables, and 6 is 2×3.")
b('kn-007', '೭ ಏಳು', "Pronounced AY-lu. The 'ḷ' is a retroflex 'l' — curl your tongue back and touch the roof of your mouth. This sound doesn't exist in English and is one of Kannada's distinctive features. Practice by saying 'lu' with your tongue curled back.")
b('kn-007', '೮ ಎಂಟು', "Pronounced EN-tu, like 'enter' without the 'er'. The nasal 'n' before 't' is natural for English speakers. Memory aid: 'eight' and 'entu' both start with 'e'. You'll hear 'entu ghante' (eight o'clock) for morning work start times.")
b('kn-007', '೯ ಒಂಬತ್ತು', "Pronounced OM-bat-tu, three syllables. The double 't' is important — hold the 't' sound slightly longer. This is the hardest number to remember because it doesn't resemble any English word. Memory aid: 'OM-bat' — imagine a bat doing yoga (om) — that's nine lives of weirdness.")
b('kn-007', '೧೦ ಹತ್ತು', "Pronounced HUT-tu (rhymes with 'put-tu'). The aspirated 'h' at the start is soft. Double 't' again — Kannada loves geminated consonants. 'Hattu rupaayi' (ten rupees) is the base unit for small purchases. Once you know 1-10, you can construct larger numbers: 'hattu-ondu' = 11, 'eradu-hattu' = 20.")

// kn-008: Food words (first 3 items shown, pattern for rest)
b('kn-008', 'ಅನ್ನ', "Pronounced UN-na with a short 'u' like 'put'. Rice is the staple food of Karnataka — most meals revolve around it. 'Anna' appears in countless phrases: 'anna-saaru' (rice with rasam), 'bisi-bele-bath' (hot lentil rice). In restaurants, just saying 'anna' gets you a plate of steamed rice. The word is so fundamental that refusing rice ('anna beda') is almost a cultural statement.")
b('kn-008', 'ರೊಟ್ಟಿ', "Pronounced ROT-ti with a rolled 'r' and doubled 't'. In Karnataka, rotti specifically means jowar (sorghum) or ragi (finger millet) flatbread — not the wheat roti of North India. 'Ragi rotti' is a Karnataka specialty: dark, nutty, and incredibly nutritious. Asking for 'rotti' in a local restaurant signals you know the regional cuisine.")
b('kn-008', 'ಸಾರು', "Pronounced SAA-ru with a long 'aa'. Saaru is Karnataka's version of rasam — a thin, tangy, spiced soup made with tamarind and tomato. It's poured over rice and eaten with the hands. Every family has their own saaru recipe, and it's often the first dish children learn to make. 'Saaru anna' (rasam rice) is comfort food for most Kannadigas.")

// kn-010: Pronouns
b('kn-010', 'ನಾನು', "Pronounced NAA-nu. The long 'aa' is important — 'nanu' (short) sounds different. This is the first word in most Kannada sentences because Kannada follows Subject-Object-Verb order. 'Naanu hogtini' = I am going. Unlike English, Kannada verbs change based on the subject, so 'naanu' is often dropped in casual speech — the verb ending tells you who's speaking.")
b('kn-010', 'ನೀನು', "Pronounced NEE-nu. Used only with close friends, younger people, or children. Using 'neenu' with an elder or stranger is considered rude — like using 'tu' instead of 'vous' in French. When in doubt, always use 'neevu' (formal you) instead. The informal/formal distinction is one of the first social rules to learn in Kannada.")
b('kn-010', 'ನೀವು', "Pronounced NEE-vu. The safe, respectful 'you' — use this with anyone you don't know well, anyone older, shopkeepers, auto drivers, colleagues. It's also used as the plural 'you' (you all). Starting with 'neevu' and switching to 'neenu' only when invited signals cultural awareness and earns respect.")
b('kn-010', 'ಅವನು', "Pronounced A-va-nu. 'He' — used for males. Kannada has three third-person pronouns where English has two: avanu (he), avalu (she), and adu (it/that). The '-nu' ending marks masculine. In casual speech, often shortened to 'avnu'. Note: pointing at someone and saying 'avanu' can be rude — use their name or a respectful title instead.")
b('kn-010', 'ಅವಳು', "Pronounced A-va-lu. 'She' — the retroflex 'ḷ' (tongue curled back) marks feminine. This is one of those sounds that distinguishes a Kannada learner from a speaker — getting the retroflex right makes a big difference. Practice: say 'lu' normally, then say it with your tongue touching the roof of your mouth further back.")
b('kn-010', 'ಅದು', "Pronounced A-du. 'It' or 'that' — used for objects, animals, and abstract things. Also used as a demonstrative: 'adu nanna pustaka' = that is my book. In casual speech, 'adu' becomes a filler word similar to English 'that' or 'it's like' — you'll hear it constantly in conversation.")
b('kn-010', 'ನಾವು', "Pronounced NAA-vu. 'We' — inclusive, meaning everyone present. Kannada doesn't distinguish between inclusive 'we' (including the listener) and exclusive 'we' (excluding the listener) like some languages do. 'Naavu hogona?' = shall we go? The '-ona' ending makes it a suggestion, like 'let's.'")
b('kn-010', 'ಅವರು', "Pronounced A-va-ru. 'They' — but also the respectful singular 'he/she.' Using 'avaru' instead of 'avanu/avalu' for a specific person shows respect, similar to the royal 'they' in English. Always use 'avaru' when referring to elders, teachers, or anyone you want to show deference to. It's the safe default for talking about third parties.")

// kn-015: Body parts (first 3)
b('kn-015', 'ತಲೆ', "Pronounced TA-le. The 't' is a dental 't' — tongue touches the back of your upper teeth, not the ridge behind them like English 't'. 'Tale novu' (headache) is one of the most useful medical phrases. In Karnataka culture, touching someone's head (especially an elder's) is a sign of deep respect — 'tale mele kai' (hand on head) is a blessing gesture.")
b('kn-015', 'ಕಣ್ಣು', "Pronounced KUN-nu. The double 'n' is held slightly longer. 'Kannu' appears in many expressions: 'kannu haaku' (to cast an eye/evil eye), 'kannu muchchu' (close your eyes). Kannada has a rich vocabulary for eye-related expressions because eyes are culturally significant — 'kannina bombe' (pupil of the eye) literally means 'doll of the eye.'")
b('kn-015', 'ಮೂಗು', "Pronounced MOO-gu. The long 'oo' distinguishes it from other words. Nose rings ('mookuthi') are traditional in Karnataka — the word comes from 'moogu' + 'uthi' (ring). 'Moogu mele kopa' (anger on the nose) is an idiom meaning someone is visibly angry — because nostrils flare when you're upset.")

// kn-016: Household items (first 3)
b('kn-016', 'ಮನೆ', "Pronounced MA-ne. One of the most important words — 'mane' means both 'house' and 'home.' 'Mane-ge hogu' = go home. 'Mane kelsa' = housework. In Kannada culture, 'mane' carries emotional weight — 'namma mane' (our home) implies family, belonging, and identity. Real estate ads in Bangalore still use 'mane' rather than English 'house' for emotional appeal.")
b('kn-016', 'ಬಾಗಿಲು', "Pronounced BAA-gi-lu. Three syllables with a long 'aa'. 'Baagilu tegeyi' = open the door. 'Baagilu hakko' = close the door (literally 'put the door'). The word 'hakko' for closing is interesting — Kannada uses 'put' where English uses 'close.' This kind of verb difference is where direct translation breaks down and you need to think in Kannada.")
b('kn-016', 'ಕಿಟಕಿ', "Pronounced KI-ta-ki. A fun word to say — the repetitive 'ki' sounds make it easy to remember. 'Kitaki tegeyi' = open the window. In traditional Karnataka homes, windows were small to keep out heat; modern apartments have larger ones. The word is the same across formal and informal speech — no respectful variant needed for objects.")

// kn-026: Question words
b('kn-026', 'ಯಾರು', "Pronounced YAA-ru. 'Who' — the most common question word. 'Yaaru neevu?' = who are you? 'Yaaru bandru?' = who came? Note that Kannada question words usually start with 'ya-' — yaaru (who), yaavaga (when), yaake (why), yelli (where). Once you spot this pattern, question words become much easier to recognize in conversation.")
b('kn-026', 'ಏನು', "Pronounced AY-nu. 'What' — used constantly. 'Enu beku?' = what do you want/need? This is perhaps the most useful phrase in daily life — shopkeepers, auto drivers, and restaurant servers will ask you this. 'Enu aaytu?' = what happened? is the standard response when someone looks upset or surprised.")
b('kn-026', 'ಎಲ್ಲಿ', "Pronounced EL-li. 'Where' — essential for navigation. 'Majestic elli?' = where is Majestic (the central bus station)? 'Neevu elli-inda?' = where are you from? The '-inda' suffix means 'from' — Kannada uses suffixes where English uses prepositions. 'Elli' + '-ige' = 'to where' (ellege hogbeku? = where should I go?).")
b('kn-026', 'ಯಾವಾಗ', "Pronounced YAA-vaa-ga. 'When' — three syllables. 'Yaavaga bartira?' = when will you come? 'Yaavaga beku?' = when do you need it? Time-related questions are important for scheduling — 'yaavaga' is more polite than 'yeshtu hottige' (at what time), which is more direct.")
b('kn-026', 'ಯಾಕೆ', "Pronounced YAA-ke. 'Why' — simple and direct. 'Yaake barl-illa?' = why didn't you come? Be careful with tone — 'yaake?' can sound accusatory. Adding 'guru' (informal address) or 'sir/madam' softens it: 'yaake guru?' = why, buddy? Children's favorite word in Kannada, just like in English.")
b('kn-026', 'ಹೇಗೆ', "Pronounced HAY-ge. 'How' — used for method and manner. 'Hege madodu?' = how to do it? 'Hege iddira?' = how are you? (formal). This is the standard greeting — responding 'chennagiddini' (I'm fine) completes the exchange. 'Hege' also works for 'how much' in casual speech, though 'yeshtu' is more precise.")
b('kn-026', 'ಎಷ್ಟು', "Pronounced YESH-tu. 'How much/how many' — essential for shopping. 'Yeshtu?' alone means 'how much does it cost?' 'Yeshtu jana?' = how many people? The 'sh' is a retroflex sound — tongue curled back. In markets, just pointing at something and saying 'yeshtu?' is perfectly acceptable and understood.")
b('kn-026', 'ಯಾವುದು', "Pronounced YAA-vu-du. 'Which one' — used when choosing between options. 'Yaavudu beku?' = which one do you want? 'Yaav bus?' = which bus? (shortened form). In restaurants with thali (meal plate) options, 'yaavudu?' helps you choose between veg and non-veg, or between different meal types.")

// kn-031: Colors (first 3)
b('kn-031', 'ಕೆಂಪು', "Pronounced KEM-pu. Red — associated with auspiciousness in Karnataka culture. 'Kempu' appears in place names: Kempe Gowda (Bangalore's founder), Kempegowda Bus Station. Brides wear red ('kempu seere' = red sari). The kumkum (red dot) on the forehead is 'kempu bottu.' Knowing color words helps in shopping — 'kempu banna beku' = I want red color.")
b('kn-031', 'ನೀಲಿ', "Pronounced NEE-li. Blue — a straightforward word. 'Neeli aakaasha' = blue sky. Karnataka's state bird, the Indian Roller, is called 'neelakantha' (blue-throated one). In textile shopping, 'neeli' covers all shades of blue — for specific shades, you'd add qualifiers like 'light neeli' or 'dark neeli.'")
b('kn-031', 'ಹಸಿರು', "Pronounced HA-si-ru. Green — literally related to 'hasi' meaning 'fresh/raw.' 'Hasiru' describes both the color and freshness: 'hasiru tarkari' = fresh/green vegetables. Karnataka's lush Western Ghats are described as 'hasiru swarga' (green paradise). The connection between green and freshness is built into the language itself.")

// ============================================================
// GUITAR PRACTICE
// ============================================================

// gp-056: Open strings
b('gp-056', '6th string (thickest)', "The low E string is your anchor — it's the deepest note on the guitar and the root of countless riffs and bass lines. When tuning, always start here. The string should vibrate slowly enough that you can almost see it move. Mnemonic for all strings: 'Eddie Ate Dynamite Good Bye Eddie' (E-A-D-G-B-E). The low E and high E are the same note two octaves apart.")
b('gp-056', '5th string', "The A string is where most barre chords and power chords are rooted. When you play an A-shaped barre chord, this string carries the root note. It's also the reference string for tuning: the 5th fret of the low E should match the open A string. If you're learning bass lines, the A string is where most of the action happens in rock and pop music.")
b('gp-056', '4th string', "The D string sits right in the middle of the guitar's range — it's the workhorse string for rhythm playing. Open D is the root of the D major chord, one of the first chords beginners learn. Many folk and country songs use open D tuning (DADF#AD) for a rich, resonant sound. When fingerpicking, your middle finger typically handles this string.")
b('gp-056', '3rd string', "The G string is the most problematic string for tuning — it's where the guitar's intonation issues are most noticeable. It's also the thinnest wound string (on acoustic) or the thickest plain string (on electric), which makes it feel different from its neighbors. Many guitarists find the G string goes out of tune fastest. Tip: when tuning, always tune UP to the note, never down — this keeps tension consistent.")
b('gp-056', '2nd string', "The B string is crucial for chord voicings — it often carries the 'color' notes that make chords sound major, minor, or jazzy. It's a plain (unwound) steel string, so it has a brighter, thinner tone than the wound strings below it. The B string is offset from the pattern of the other strings: while most adjacent strings are tuned in 4ths (5 frets apart), G to B is a major 3rd (4 frets). This irregularity is why chord shapes shift when they cross the G-B boundary.")
b('gp-056', '1st string (thinnest)', "The high E string is where melodies live. It's the same note as the 6th string but two octaves higher. Because it's the thinnest string, it's the easiest to bend (push sideways to raise the pitch) — bending on the high E is fundamental to blues and rock soloing. It's also the most fragile string and breaks most often. Keep spares. When strumming, the high E adds sparkle and brightness to chords.")

// gp-057: Low E string notes
b('gp-057', 'Fret 0 (open)', "Open E is the lowest standard note on the guitar. It's the root of E major and E minor — two of the most common guitar chords. Many iconic riffs start on open E: the opening of 'Smoke on the Water' (sort of), 'Iron Man,' and countless metal songs. When you're lost on the fretboard, the open E is home base. Learn to hear this pitch and you'll always be able to orient yourself.")
b('gp-057', 'Fret 1', "F is just one fret up from open E — a half step. The F note on the first fret is important because F major is one of the hardest beginner chords (it requires a barre). Knowing that F lives here helps you understand WHY the barre chord shape works. This is also where the famous 'Jaws' theme starts — that menacing half-step between E and F.")
b('gp-057', 'Fret 3', "G on the third fret is a power note — it's the root of G major, one of the most common keys in popular music. The distance from E to G (3 frets) is a minor third interval, which has a dark, moody sound. Many blues riffs use the E-G movement. Tip: the 3rd fret on the low E string is also where you'd put your finger for a G power chord (G5).")
b('gp-057', 'Fret 5', "A on the fifth fret is a crucial reference point: it should sound exactly like the open A string (5th string). This is the most basic tuning check. The 5th fret = next string relationship works for all strings except G to B (which is 4th fret). Memorize this: 5th fret of any string = the open string below it (except G→B which is 4th fret).")
b('gp-057', 'Fret 7', "B on the seventh fret. The distance from A (fret 5) to B (fret 7) is a whole step — two frets. B is the fifth of E, which means playing E and B together sounds powerful and stable. This is the basis of power chords: root + fifth. Every time you play a power chord, you're using this root-fifth relationship.")
b('gp-057', 'Fret 8', "C on the eighth fret. C is one of the most important notes in music — it's the 'home base' of music theory because the C major scale has no sharps or flats. On the low E string, C at fret 8 is useful for walking bass lines and for understanding how the fretboard connects to music theory. The distance from B (fret 7) to C (fret 8) is a half step — B and C are natural half steps, just like E and F.")
b('gp-057', 'Fret 10', "D on the tenth fret. You're getting high up the neck now. D is the root of D major — but up here, it's an octave higher than the open D string (4th string). This equivalence is useful: any note you know on one string exists on other strings at different frets. Learning the fretboard means building a mental map of where the same note appears in different positions.")
b('gp-057', 'Fret 12', "E on the twelfth fret — you've come full circle. The 12th fret is ALWAYS the same note as the open string, one octave higher. This is true for every string. The 12th fret is marked with double dots on most guitars for exactly this reason. Everything above fret 12 repeats the pattern from frets 0-11. If you know the first 12 frets, you know the entire fretboard.")

// gp-058: A string notes (first few)
b('gp-058', 'Fret 0 (open)', "Open A is the root of A major and A minor — two essential chords. The A note is the universal tuning reference: orchestras tune to A440 (A at 440 Hz). Your open A string should be 110 Hz (two octaves below concert A). Many tuner apps show the frequency, which helps you understand the physics of pitch. A is also the starting point for the A minor pentatonic scale — the first scale most guitarists learn for soloing.")
b('gp-058', 'Fret 2', "B on the second fret of the A string. This is where B-rooted barre chords live — B major and B minor barre chords start here. B is a common key in pop music (especially with a capo). The distance from A to B (2 frets = whole step) is the same as E to F# or D to E. Recognizing these whole-step intervals helps you navigate the fretboard by sound, not just by memorized positions.")
b('gp-058', 'Fret 3', "C on the third fret of the A string is one of the most important notes to memorize. It's the root position for C-shaped barre chords and the starting point for the C major scale in this position. Since C major has no sharps or flats, it's the 'default' key for understanding music theory. Many guitarists learn the fretboard by first memorizing all the C positions across all strings.")
b('gp-058', 'Fret 5', "D on the fifth fret — same tuning trick as before: 5th fret of A should match the open D string. D is the root of D major, a bright and popular key for acoustic guitar. This position is also where D-rooted barre chords begin. Notice the pattern: 5th fret always gives you the next string's open note (except G→B). This single rule lets you find notes quickly across the fretboard.")

// gp-060: All notes on low E (sample)
b('gp-060', 'E (open)', "Home position. Let the string ring open and listen to the pitch — this is your reference point for the entire low E string. Try to memorize this sound so you can tune by ear. Hum the note, then play it. When they match, your ear training has begun. Every note on this string is measured in distance from this open E.")
b('gp-060', 'F (fret 1)', "One half step up from E. The E-F half step is one of only two natural half steps in music (the other is B-C). This means there's no sharp or flat between E and F — they're right next to each other. This is why the F chord is at fret 1, not fret 2. Understanding natural half steps is the key to understanding why the fretboard is laid out the way it is.")
b('gp-060', 'F# (fret 2)', "F sharp — one half step above F, one whole step above E. The '#' means 'raised by one fret.' F# is the same note as Gb (G flat) — they're 'enharmonic equivalents,' two names for the same pitch. Whether you call it F# or Gb depends on the musical context. For guitar, just know: fret 2 on the low E is F#/Gb.")

// gp-068: Octave shapes
b('gp-068', 'E string → D string', "From any note on the low E string, the same note one octave higher is 2 frets up and 2 strings over (on the D string). Example: E at fret 0 → E at fret 2 on D string. This shape is incredibly useful for finding notes quickly. If you know where G is on the E string (fret 3), you instantly know where the higher G is (fret 5 on D string). Practice this shape until it's automatic.")
b('gp-068', 'A string → G string', "Same shape works from the A string to the G string: 2 frets up, 2 strings over. A at fret 0 → A at fret 2 on G string. This octave shape is the basis of many bass lines and riffs — playing a note and its octave together creates a full, powerful sound. The Red Hot Chili Peppers' bassist Flea uses octave shapes constantly.")
b('gp-068', 'D string → B string', "Here's where it gets tricky: because of the G-to-B tuning irregularity, the octave shape from the D string to the B string is 3 frets up and 2 strings over (not 2 frets like before). D at fret 0 → D at fret 3 on B string. This one-fret shift catches many guitarists off guard. Memorize it: any shape that crosses the G-B boundary shifts up by one fret.")
b('gp-068', 'G string → high E', "From the G string to the high E string: 3 frets up, 2 strings over (same shift as D→B because you're crossing the G-B boundary). G at fret 0 → G at fret 3 on high E. Once you internalize both octave shapes (2-fret jump for E/A strings, 3-fret jump when crossing G-B), you can find any note's octave instantly anywhere on the fretboard.")

// gp-074: Interval shapes
b('gp-074', 'Minor 3rd', "A minor third is 3 frets up from any note on the same string. It's the interval that makes minor chords sound sad or dark. Play any note, then the note 3 frets higher — that melancholy sound is a minor third. The opening of 'Greensleeves' or 'Hey Jude' (the 'Jude' leap) uses a minor third. On the fretboard, minor thirds are easy to see: just count 3 frets.")
b('gp-074', 'Major 3rd', "A major third is 4 frets up — one fret more than a minor third. This single fret difference is what separates happy from sad in music. Play a note and go up 4 frets: that bright, cheerful sound is a major third. The opening of 'When the Saints Go Marching In' starts with a major third. The difference between a major and minor chord is literally this one fret — the third is either 3 or 4 frets from the root.")
b('gp-074', 'Perfect 5th', "A perfect fifth is 7 frets up — or equivalently, 2 frets up on the next lower string. This is the most consonant interval after the octave, and it's the basis of power chords. Play any note and the note 7 frets higher: that strong, stable, 'powerful' sound is a fifth. Power chords (used in rock, punk, metal) are just root + fifth. The fifth is so stable that it works over almost any chord — it's the safest note to play when you're unsure.")
b('gp-074', 'Perfect 4th', "A perfect fourth is 5 frets up — and here's the magic: 5 frets up on any string is the same as the open next string (except G→B which is 4 frets). This is why standard tuning works the way it does — each string is a perfect fourth above the one below it. The fourth has a 'suspended' quality — it wants to resolve. The opening of 'Here Comes the Bride' is a perfect fourth. In guitar terms, the fourth is your tuning interval.")

// gp-096: Fingerpicking assignments
b('gp-096', 'p (thumb)', "The thumb (pulgar in Spanish, hence 'p') handles the three bass strings: E, A, and D. It moves differently from the fingers — it pushes downward and away from the palm, while fingers pull upward. The thumb provides the bass line and rhythm foundation in fingerpicking. In classical technique, the thumb should be slightly ahead of the fingers, creating a 'shelf' that the fingers can work from. Common mistake: letting the thumb collapse inward instead of staying extended.")
b('gp-096', 'i (index)', "The index finger (indice) is assigned to the G string (3rd string). It's your most controlled finger and often carries the melody in fingerpicking patterns. The motion should come from the last knuckle — curl the fingertip toward the palm to pluck, then release. Avoid pulling the string away from the guitar body; instead, push through the string and come to rest on the next string. This 'rest stroke' produces a fuller, louder tone.")
b('gp-096', 'm (middle)', "The middle finger (medio) handles the B string (2nd string). It's typically your strongest finger and alternates with the index for fast passages. The i-m alternation is the foundation of classical guitar speed technique — practice alternating i-m on a single string until it's effortless. Many fingerpicking patterns use a 'pinch' where the thumb and middle finger play simultaneously, creating a bass-melody combination.")
b('gp-096', 'a (ring)', "The ring finger (anular) is assigned to the high E string (1st string). It's the weakest of the picking fingers and needs the most practice to develop independence. A common exercise: hold a chord and play p-i-m-a in sequence, making each note equally loud. The ring finger tends to move with the middle finger — developing independence between 'm' and 'a' is one of the biggest challenges in fingerpicking. Daily practice of a-m alternation helps enormously.")

// gp-114: Interval songs
b('gp-114', 'Minor 2nd (1 fret)', "The minor second — just one fret — is the most dissonant common interval. It's the 'Jaws' theme: that creeping, menacing half-step. It's also the first two notes of 'Für Elise' by Beethoven. On guitar, play any fret then the next fret up — that tense, clashing sound is a minor second. In horror movie scores, minor seconds are everywhere because they trigger an instinctive unease.")
b('gp-114', 'Major 2nd (2 frets)', "Two frets apart — a whole step. This is the interval between most adjacent notes in a major scale (do-re, re-mi, fa-sol, etc.). The first two notes of 'Happy Birthday' form a major second. It sounds neutral and stepwise — neither happy nor sad, just movement. On guitar, two frets is the most common distance you'll move when playing scales.")
b('gp-114', 'Minor 3rd (3 frets)', "Three frets — the sad interval. The opening of 'Greensleeves,' the 'Hey' to 'Jude' in Hey Jude, or the NBC chime (first two notes). Minor thirds are the building blocks of minor chords and give blues its characteristic melancholy. When you hear a melody that tugs at your emotions, there's often a minor third lurking in it.")
b('gp-114', 'Major 3rd (4 frets)', "Four frets — the happy interval. The first two notes of 'When the Saints Go Marching In' or 'Kumbaya.' Major thirds make major chords sound bright and cheerful. The difference between major and minor — between happy and sad in music — is literally one fret: 3 frets (minor) vs 4 frets (major). Train your ear to hear this difference and you'll understand harmony intuitively.")
b('gp-114', 'Perfect 4th (5 frets)', "Five frets — the 'Here Comes the Bride' interval. Also the opening of 'Amazing Grace.' The perfect fourth has a strong, open quality. On guitar, it's special because it's the tuning interval between most adjacent strings. When you tune your guitar using the 5th-fret method, you're matching perfect fourths. This interval appears in countless melodies and is one of the easiest to recognize by ear.")
b('gp-114', 'Perfect 5th (7 frets)', "Seven frets — the 'Star Wars' theme opening, or 'Twinkle Twinkle Little Star.' The perfect fifth is the most consonant interval after the octave — it sounds stable, powerful, and complete. Power chords are built on fifths. The fifth is so fundamental that it appears in virtually every musical tradition worldwide. If you can only recognize one interval by ear, make it the fifth.")
b('gp-114', 'Octave (12 frets)', "Twelve frets — the same note, higher. The opening of 'Somewhere Over the Rainbow' is an octave leap. An octave sounds like the 'same note but different' — your brain perceives octaves as equivalent pitches. This is why the 12th fret has double dots: it's where the fretboard pattern repeats. Training your ear to recognize octaves is the foundation of all interval recognition — once you can hear 'same note, different height,' other intervals become easier to distinguish.")

// gp-120: Intervals on A string (first few)
b('gp-120', 'A to B (fret 5→7)', "A whole step — 2 frets. This is a major second interval. Play fret 5 (A), then fret 7 (B). Listen to the 'stepping up' quality. This is the same interval as the first two notes of a major scale (do to re). Practice: play A, sing what you think B sounds like, then play B to check. This ear training exercise builds the connection between what you hear internally and what you play.")
b('gp-120', 'A to C (fret 5→8)', "A minor third — 3 frets. This is the interval that makes A minor sound sad. Play A then C and notice the melancholy quality. Now play A then C# (fret 9) — that's a major third, and it sounds bright. The difference between these two — one single fret — is the entire difference between major and minor. This is arguably the most important ear training distinction in all of Western music.")
b('gp-120', 'A to D (fret 5→10)', "A perfect fourth — 5 frets. This should sound like the open D string (and it is the same note). The fourth has a 'suspended' quality — it wants to move somewhere. In the key of A, D is the fourth degree, and the movement from A to D (I to IV) is one of the most common chord changes in all popular music. Blues, rock, country, and folk all use the I-IV movement constantly.")

// gp-123: Chords in a key (first few)
b('gp-123', 'I - G major', "The I chord is 'home' — the tonic. In the key of G, G major is where songs begin and end. It feels resolved, stable, complete. When you hear a song end on the I chord, your ear relaxes — you've arrived. The I chord defines the key: if a song keeps returning to G major, you're in the key of G. About 90% of pop songs end on the I chord. Learning to hear 'home' is the foundation of understanding harmony.")
b('gp-123', 'ii - A minor', "The ii chord (lowercase = minor) adds gentle tension. In the key of G, A minor is the ii chord. It has a softer, more contemplative quality than the I chord. The ii chord often leads to the V chord (D major) in a ii-V-I progression — one of the most common chord movements in jazz and pop. 'Autumn Leaves' and countless jazz standards use ii-V-I. On guitar, the Am shape is one of the first chords you learn.")
b('gp-123', 'iii - B minor', "The iii chord is the most mysterious chord in a major key. B minor in the key of G has a dark, introspective quality. It's used less frequently than I, IV, V, or vi, which makes it stand out when it appears. Radiohead and other art-rock bands love the iii chord for its unexpected emotional color. It shares two notes with the I chord (G major: G-B-D; B minor: B-D-F#) which is why it can substitute for I in certain progressions.")
b('gp-123', 'IV - C major', "The IV chord is the 'lift' — it creates gentle forward motion away from home. In the key of G, C major is the IV chord. The I-IV movement (G to C) is the most common two-chord change in popular music. 'Let It Be,' 'No Woman No Cry,' and thousands of folk songs use I-IV as their foundation. The IV chord feels like taking a step forward — not tense, but not home either. It's the musical equivalent of 'and then...'")
b('gp-123', 'V - D major', "The V chord creates the strongest pull back to home (I). In the key of G, D major is the V chord, and the V-I movement (D to G) is the most powerful resolution in Western music. It's called the 'authentic cadence' and it signals 'the end' in classical music. The V chord contains a note (F# in D major) that desperately wants to resolve up to G — this tension-and-release is what makes music feel like it's going somewhere.")
b('gp-123', 'vi - E minor', "The vi chord is the 'sad relative' of the I chord. E minor in the key of G shares two notes with G major (G-B-D vs E-G-B), which is why they sound related but emotionally different. The I-V-vi-IV progression (G-D-Em-C) is the most common chord progression in pop music — 'Let It Be,' 'No Woman No Cry,' 'With or Without You,' 'Someone Like You' all use it. The vi chord is where the emotional weight lives in this progression.")
b('gp-123', 'vii° - F# diminished', "The vii° (diminished) chord is the rarest and most unstable chord in a major key. F# diminished in the key of G sounds tense and unresolved — it desperately wants to move to the I chord. Most pop and rock songs avoid it entirely, substituting the V chord instead. But in jazz and classical music, the vii° appears regularly as a passing chord. Its instability is useful: it creates maximum tension before a resolution. Think of it as the musical equivalent of a cliffhanger.")

// gp-147: Circle of fifths (first few)
b('gp-147', 'C major (0 sharps)', "C major is the 'white keys' key — no sharps, no flats. It's the starting point of the circle of fifths and the default key for learning music theory. On guitar, C major is played in open position with one of the first chord shapes you learn. The key of C is bright and straightforward, which is why children's songs and music theory examples almost always use it. Every other key is defined by how many sharps or flats it adds relative to C.")
b('gp-147', 'G major (1 sharp: F#)', "Moving clockwise on the circle, G major adds one sharp: F#. This is the most popular key for acoustic guitar because the open chord shapes (G, C, D, Em, Am) all fall naturally under the fingers. The F# means every F in the key is raised by one fret. On guitar, you rarely think about this consciously — the chord shapes handle it automatically. But knowing that G major has F# helps when you're figuring out melodies by ear.")
b('gp-147', 'D major (2 sharps: F#, C#)', "D major adds C# to G major's F#. It's a bright, ringing key on guitar — the open D and A strings resonate naturally. Many country and folk songs are in D major. The two sharps mean F and C are always raised. When soloing in D major, avoid natural F and C — they'll sound 'wrong' against D major chords. The D major scale on guitar has a comfortable box shape starting at the 2nd fret.")
b('gp-147', 'A major (3 sharps: F#, C#, G#)', "A major adds G# to D major's sharps. It's a popular key for rock and blues — AC/DC's 'Back in Black' is in A major. Three sharps means F, C, and G are all raised. The open A string gives this key a powerful bass foundation. The A major pentatonic scale (A-B-C#-E-F#) is one of the most useful scales for soloing over A major chord progressions.")
b('gp-147', 'E major (4 sharps)', "E major has four sharps: F#, C#, G#, D#. It's the quintessential rock guitar key because the open low E string provides a massive bass note. 'Johnny B. Goode,' 'Sunshine of Your Love,' and countless blues songs are in E. The E major and E minor pentatonic scales are usually the first scales guitarists learn for soloing. The key of E lets you use all six open strings, creating a full, resonant sound.")
b('gp-147', 'B major (5 sharps)', "B major has five sharps — only F and C remain natural. It's less common on guitar because there's no convenient open B chord (you need a barre chord). However, with a capo on the 2nd fret, you can play in B major using A-shaped open chords. Many pop songs in B major are played this way. The key of B is bright and energetic, popular in K-pop and modern pop production where guitars are often capoed up.")

// ============================================================
// MERGE LOGIC — apply bodies to JSON files
// ============================================================

function enrichFile(filePath) {
  const data = JSON.parse(readFileSync(new URL(filePath, import.meta.url), 'utf-8'))
  let enriched = 0, skipped = 0
  data.forEach(task => {
    if (task.reference?.type !== 'structured_list') return
    task.reference.items.forEach(item => {
      const key = task.id + '::' + item.primary
      if (bodies[key]) {
        item.body = bodies[key]
        enriched++
      } else {
        skipped++
      }
    })
  })
  writeFileSync(new URL(filePath, import.meta.url), JSON.stringify(data, null, 2), 'utf-8')
  console.log(`${filePath}: ${enriched} enriched, ${skipped} skipped`)
}

console.log(`Body entries: ${Object.keys(bodies).length}`)
enrichFile('../data/philosophy.json')
enrichFile('../data/learn_kannada.json')
enrichFile('../data/guitar_practice.json')
